82	// objectStoreMapAdapter wraps maps of types.NamespacedName to Kubernetes resources
83	// (e.g. map[types.NamespacedName]*v1.Gateway) so that they can be used through objectStore interface.
84	type objectStoreMapAdapter[T client.Object] struct {
