115	// convertingReferenceGrantStore converts v1beta1 ReferenceGrant objects to v1 before storing them.
116	// This allows the system to handle v1beta1 ReferenceGrants transparently when the v1 CRD is not available.
117	type convertingReferenceGrantStore struct {
118		v1Store *objectStoreMapAdapter[*gatewayv1.ReferenceGrant]
119	}
120	
121	func newConvertingReferenceGrantStore(
122		objects map[types.NamespacedName]*gatewayv1.ReferenceGrant,
123	) *convertingReferenceGrantStore {
124		return &convertingReferenceGrantStore{
125			v1Store: newObjectStoreMapAdapter(objects),
126		}
127	}
128	
129	func (s *convertingReferenceGrantStore) get(objType ngftypes.ObjectType, nsname types.NamespacedName) client.Object {
130		return s.v1Store.get(objType, nsname)
131	}
132	
133	func (s *convertingReferenceGrantStore) upsert(obj client.Object) {
134		beta, ok := obj.(*gatewayv1beta1.ReferenceGrant)
135		if !ok {
136			panic(fmt.Errorf("obj type mismatch: got %T, expected *v1beta1.ReferenceGrant", obj))
137		}
138	
139		converted := &gatewayv1.ReferenceGrant{
140			ObjectMeta: beta.ObjectMeta,
141		}
142		// Copy spec fields. The v1beta1 and v1 types share identical From/To structures.
143		for _, from := range beta.Spec.From {
144			converted.Spec.From = append(converted.Spec.From, gatewayv1.ReferenceGrantFrom{
145				Group:     from.Group,
146				Kind:      from.Kind,
147				Namespace: from.Namespace,
148			})
149		}
150		for _, to := range beta.Spec.To {
151			var name *gatewayv1.ObjectName
152			if to.Name != nil {
153				n := *to.Name
154				name = &n
155			}
156			converted.Spec.To = append(converted.Spec.To, gatewayv1.ReferenceGrantTo{
157				Group: to.Group,
158				Kind:  to.Kind,
159				Name:  name,
160			})
161		}
162	
163		s.v1Store.upsert(converted)
164	}
